var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"바이탈 체크…! 체온, 호흡, 맥박, 혈압 모두 불안정합니다!","JPN":"バイタルチェック……！　体温、呼吸、脈、血圧、全部不安定です！","ENG":"Checking vitals...! Body temperature, breathing, pulse, and blood pressure all unstable!","TWN":"生命徵兆檢查…！體溫、呼吸、脈搏、血壓都不穩定！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP3"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"안정화 시도하고 마취의 대기시켜! 여차하면 응급 수술 들어가야 해!","JPN":"安定化を試みて、麻酔医の待機を！　いざとなれば緊急手術だ！","ENG":"Begin stabilization! Prep the anesthesia! If it gets worse, we'll need emergency surgery!","TWN":"嘗試穩定病情，準備麻醉！如果情況緊急，就要進行緊急手術！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"주교님의 상태는 어떤가요?","JPN":"主教の状態はいかがですか？","ENG":"How is the Bishop?","TWN":"主教的狀態怎麼樣？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DOCTOR_PRIDE_NULL_NULL","text":{"KOREA":"고비는 넘기셨지만 아직 의식이 불분명하십니다.","JPN":"危険な状態は脱しましたが、まだ意識がはっきりとしていません。","ENG":"He's past the worst of it, but still unconscious.","TWN":"雖然度過了危機，但意識仍然不清晰。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOCTOR_PRIDE_NULL_NULL","text":{"KOREA":"당분간은… 상태를 지켜봐야 할 것 같군요.","JPN":"しばらくは……様子見ですね。","ENG":"We'll have to... keep monitoring him for now.","TWN":"暫時……還是觀察一下情況吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOCTOR_PRIDE_NULL_NULL","text":{"KOREA":"메데이아 경, 괜찮으십니까?","JPN":"メデイア卿、大丈夫ですか？","ENG":"Dame Medea, are you all right?","TWN":"美狄亞，你沒事吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"아무것도 아닙니다. 수술, 고생 많으셨어요.","JPN":"何でもありません。手術、お疲れ様でした。","ENG":"Don't mind me. You've done well with the surgery.","TWN":"沒什麼。手術，辛苦了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"주교님이 의식을 되찾으시면 제게 연락 부탁드립니다.","JPN":"主教が意識を取り戻したら、私にご連絡をお願いします。","ENG":"Please contact me as soon as the Bishop regains consciousness.","TWN":"請在主教恢復意識後聯絡我。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"……하.","JPN":"……は。","ENG":"*...Sigh*","TWN":"……哈。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"본부에 배신자가 있었다고요?","JPN":"本部に裏切り者がいた？","ENG":"You're telling me there was a traitor inside HQ?","TWN":"本部還有背叛者嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"그래. 이전부터 레드시프트와 긴밀한 관계를 유지한 모양일세.","JPN":"ああ。昔からレッドシフトと緊密な関係を維持していたようだ。","ENG":"Yes. It seems they've maintained close ties with Red Shift for some time.","TWN":"是啊，看起來從以前開始就和紅移保持著密切的關係。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"작전 유출과 작전 팀의 채널 송신 차단도 그들의 개입이었던 모양이야.","JPN":"作戦の流出と作戦チームのチャンネル送信遮断も、彼らの介入だったらしい。","ENG":"They were behind both the leaked plans and the jamming of the operation team's comms.","TWN":"作戰洩露和作戰隊的頻道發送阻斷似乎也是他們的介入。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"그걸 지금…… 말이라고 하시는 건가요?","JPN":"冗談でしょう？","ENG":"And you're... just now telling me this?!","TWN":"你……怎麼可以這麼說呢？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"이번 작전에 사활이 걸려있단 걸 아시면서 그런 무책임한 소리를…!!","JPN":"今回の作戦に生死がかかっていると知りながら、そんな無責任な話……！！","ENG":"You knew this operation was everything, and yet you speak so carelessly...!!","TWN":"明知道這次作戰關乎生死，你怎麼能說出這麼不負責任的話…！！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"글쎄. 이제 와서는 의문이 드는군.","JPN":"どうだか。今になっては疑問だ。","ENG":"Well. At this point, I have to wonder.","TWN":"這個嘛，現在才開始覺得疑惑。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"만약 작전대로 풀렸다면 우리가 이길 수 있었을까?","JPN":"もし作戦どおりになっていたら、私たちは勝利できただろうか？","ENG":"Even if things had gone according to plan, could we really have won?","TWN":"如果按照計畫進行，我們能贏嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"……네?","JPN":"……はい？","ENG":"...What?","TWN":"……嗯？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"기사단은 그림자 전문이나 그것이 인간을 죽이는데 능통하다는 것은 아니야.","JPN":"騎士団はシャドウ専門だが、それが人間を殺すことに長けているという意味ではない。","ENG":"The Order specializes in killing Shadows, not humans.","TWN":"騎士團擅長對付暗影，但這並不意味著他們擅長殺人。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"지키는 입장에 선 기사가 어찌 생사결을 벌일 수 있겠나?","JPN":"守る立場にある騎士が、はたして生死を決する戦いをこなせるだろうか。","ENG":"How can a knight, sworn to protect, engage in a duel to the death?","TWN":"站在守護立場的騎士怎麼能進行生死決鬥呢？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"처음부터 이 싸움 자체가 단원들에게 무거운 짐이었던 거야.","JPN":"最初からこの戦い自体が、団員には荷が重かったのだよ。","ENG":"This war has been a burden from the very start.","TWN":"從一開始，這場戰鬥對成員們來說就是沉重的負擔。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"프레이더 경. 지금 레드시프트에게 투항하자는 겁니까?","JPN":"フレイダー卿。今、レッドシフトに投降しようというのですか？","ENG":"Sir Frayder. Are you suggesting we surrender to Red Shift?","TWN":"弗雷德。你是說現在要向紅移投降嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"그들의 목적은 기사단이 아니야. 별의 무구일 뿐이지.","JPN":"彼らの目的は騎士団ではない。星の武具だ。","ENG":"Their goal isn't the Order. It's the Star Armaments.","TWN":"他們的目的不是騎士團，而是星之武具。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"설령 기사단이 추구해온 정의에 위반되는 일이라 한들.","JPN":"たとえ騎士団が追求してきた正義に反することであっても。","ENG":"Even if that goes against the justice we've upheld...","TWN":"即便是違反了騎士團所追求的正義之事。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"후일을 위해 일보 후퇴하는 것을, 현 시점에서 어찌 고려하지 않겠는가?","JPN":"後日のための一歩後退を、現時点で考慮しない理由はない。","ENG":"Shouldn't we at least consider a tactical retreat, for the future's sake?","TWN":"為了將來而暫時退一步，現階段怎麼能不考慮呢？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"……수년간 기사단에 내재해 있던 불안 요소들이 일제히 터져버렸어.","JPN":"数年間、騎士団に内在していた不安要素が一斉に爆発してしまった。","ENG":"All the underlying tensions in the Order have exploded at once.","TWN":"……多年來潛藏在騎士團中的不安因素突然爆發了。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L38_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"당장의 내부전력만으로 일을 처리하기에는… 한계가 온 거야.","JPN":"今の内部戦力だけで事態を収めるには……限界が来たのよ。","ENG":"We've hit our limit... We can't handle this with internal forces alone.","TWN":"僅憑現有的內部力量來處理事情…已經到了極限。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"누님. 괜찮으신가요?","JPN":"メデイアさん、大丈夫ですか？","ENG":"Medea, are you all right?","TWN":"姊姊。你沒事吧？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"기분 나빠. 저리 가, 안경.","JPN":"気分が悪いわ。あっちに行ってて、眼鏡。","ENG":"You're annoying. Go away, Glasses.","TWN":"煩人，走開，眼鏡。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"죄송합니다. 저도 그러고 싶지만 부단장님이 깨어나셨어요.","JPN":"すみません。私もそうしたいんですけど、副団長が目覚めたんです。","ENG":"Sorry, I wish I could but I can't. Deputy has woken up.","TWN":"對不起。我也想這樣做，但副團長已經醒來了。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"부단장님이 누님을 찾고 계십니다.","JPN":"メデイアさんを探していました。","ENG":"She's asking for you.","TWN":"副團長正在找姊姊。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"피오네가? 나를?","JPN":"フィオネが？　私を？","ENG":"Fione? She's asking for me?","TWN":"菲奧尼？找我？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"안내해. 그리로 갈 테니까.","JPN":"案内しなさい。そっちに行くから。","ENG":"All right. Take me to her.","TWN":"帶路吧，我會去那裡的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"크윽…!!","JPN":"くっ……！！","ENG":"Kgh...!!","TWN":"咳呃……！！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L2_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"무리하지 마, 부단장! 그러다 또 쓰러지면 어쩌려고 그래?","JPN":"無理しないで、副団長！　それでまた倒れたらどうするの？","ENG":"Easy there, Deputy! What if you collapse again?!","TWN":"別太勉強了，副團長！要是又累倒了怎麼辦？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"문제없습니다. 움직이는데 조금 불편해도 상처는 대부분 회복됐어요.","JPN":"問題ありません。動くのは少し不便ですが、怪我はほとんど治りました。","ENG":"I'm fine. Moving around is a bit uncomfortable, but most of my injuries have healed.","TWN":"沒問題。雖然行動有些不便，但傷口大部分已經恢復了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"에리어스 경이 납치당한 이상, 이대로 가만히 있을 수는 없습니다.","JPN":"アリウス卿が攫われた以上、このままじっとしているわけにはいきません。","ENG":"Dame Arius has been taken. I can't just sit here doing nothing.","TWN":"埃里奧斯卿被綁架了，我們不能坐視不管。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"누가 몰라서 그래? 딱 봐도 무리하고 있으니까 그렇지!","JPN":"それはわかってるよ。でも無理してるから！","ENG":"You think we don't know that?! But anyone can see you're still overdoing it!","TWN":"誰不知道呢？一看就知道你在勉強自己！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"부단장님, 말씀대로 메데이아 경을 모셔왔습니다.","JPN":"副団長、言われたとおりメデイア卿をお連れしました。","ENG":"Deputy, as requested, I've brought Dame Medea.","TWN":"副團長，按照你的吩咐，我把美狄亞請來了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"잠시 들어가도 괜찮을까요?","JPN":"入ってもいいですか？","ENG":"May we come in?","TWN":"我可以進去一下嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"예. 들어오시죠.","JPN":"はい。どうぞお入りください。","ENG":"Yes. Please.","TWN":"是。請進來吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"죄송합니다, 메데이아 경. 바쁘실 텐데 제가 시간을 빼앗았군요.","JPN":"申し訳ありません、メデイア卿。お忙しいのに、大事なお時間をとらせてしまって。","ENG":"Forgive me, Dame Medea. I know you're busy, and I've taken up your time.","TWN":"抱歉，美狄亞。我佔用了你的時間，你一定很忙。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"설마요. 그리고 무리하실 필요 없으니 누워 계셔도 돼요.","JPN":"まさか。それに無理する必要はありませんから、横になっていてください。","ENG":"Don't be silly. And no need to get up. Lie down if you must.","TWN":"怎麼可能。而且沒有必要勉強自己，躺著也可以喔。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"전 괜찮습니다. 당장 움직이는데 아무런 문제도 없어요.","JPN":"私は大丈夫です。今すぐ動いても何の問題もありません。","ENG":"I'm fine. I'm able to move with no problem.","TWN":"我沒問題。馬上行動沒有任何問題。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"뭐?","JPN":"はあ？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"잠시만! 지금 무슨 소리를 하는 거야, 부단장?","JPN":"待ってよ！　何言ってるの、副団長？","ENG":"Hold it! What are you even saying right now, Deputy?","TWN":"等一下！這是什麼意思，副團長？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L20_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"아무런 문제도 없다니, 그런 거짓말은 왜 하는데?","JPN":"何の問題もないって、何でそんな嘘をつくの？","ENG":"Why are you lying saying that everything's fine?","TWN":"沒問題？為什麼要撒謊？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경. 부탁드립니다.","JPN":"リブ卿。お願いします。","ENG":"Please, Dame Liv.","TWN":"莉芙。拜託了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"으으. 단장이 사라지고 나서 완전 고집쟁이 다 됐다니까.","JPN":"うう。団長が消えてから意地っ張りになっちゃったよ。","ENG":"Ugh, ever since Captain vanished, you've turned into a total stubborn mule.","TWN":"唉，自從團長消失後，完全變成了一個固執鬼。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"알았어. 대신 너무 무리하지 마.","JPN":"わかったよ。でも、あまり無理しないで。","ENG":"Fine. But don't overdo it, all right?","TWN":"知道了。不要太勉強自己。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"죄송합니다. 잠시 작은 소란이 있었군요.","JPN":"申し訳ありません。少し騒がせてしまって。","ENG":"I'm sorry. That was a bit of a commotion.","TWN":"對不起，剛剛有點小騷亂。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"본론으로 돌아가, 메데이아 경을 부른 이유를 말씀드리겠습니다.","JPN":"本題に戻って、メデイア卿をお呼びした理由を説明します。","ENG":"Back to the point. I'll explain why I asked you here, Dame Medea.","TWN":"回到正題，我來告訴你召喚美狄亞的原因。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"안 돼요.","JPN":"駄目です。","ENG":"No.","TWN":"不行。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"네?","JPN":"え？","ENG":"What?","TWN":"嗯？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"레드시프트와 싸우러 갈 테니 허락해달라는 거잖아요?","JPN":"レッドシフトと戦うために行くから許してほしいということですわよね？","ENG":"You're about to ask me to authorize an assault on Red Shift, aren't you?","TWN":"你是說要去和紅移戰鬥，希望我能允許嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"절대 안 돼요. 다른 사람들은 몰라도, 당신들은 더더욱.","JPN":"絶対駄目です。他の人ならともかく、あなたたちはなおさら。","ENG":"Absolutely not. I won't allow it. Especially not you all.","TWN":"絕對不行。其他人還好說，但你們絕對不行。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"메데이아 경. 레드시프트의 단장이 에리어스를 인질로 잡고 있습니다!","JPN":"メデイア卿。レッドシフトの団長がアリウスを人質に取っています！","ENG":"Dame Medea. Red Shift's captain has taken Dame Arius hostage!","TWN":"美狄亞，紅移的團長挾持了埃里奧斯作為人質！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"어디 있을지도 모르는 레드시프트를 어떻게 찾으려고요?","JPN":"どこにいるのかも知らないレッドシフトをどうやって探すつもりですか？","ENG":"And how exactly do you plan to find Red Shift, when we don't even know where they are?","TWN":"你打算怎麼找到可能在任何地方的紅移？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"그리고 찾으면, 이길 수는 있나요? 카란티시르에게 당해 그렇게 됐으면서?","JPN":"そして見つけたら、勝てるのですか？　カランティシルにやられてそうなったのに？","ENG":"And even if you did find them, can you win? After what happened with Carantisir?","TWN":"那麼找到之後，能贏嗎？明明被卡蘭堤西爾打得那麼慘？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"에리어스가 절 구하려다 인질이 됐는데, 가만히 지켜보고 있으라는 말씀입니까?","JPN":"アリウスが私を助けようとして人質になったのに、黙って見ていろということですか？","ENG":"Dame Arius became a hostage trying to save me. Are you telling me to just sit here and do nothing?!","TWN":"埃里奧斯為了救我而被劫持為人質，你是讓我袖手旁觀嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"피오네. 기사단의 혼란이 가중되어 원로원이 소극적인 상황이에요.","JPN":"フィオネ。騎士団の混乱が大きくなり、元老院が消極的になっている状況です。","ENG":"Fione. The Order's in chaos, and the Elders are barely taking any action.","TWN":"菲奧尼。騎士團的混亂加劇，元老院處於消極狀態。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"저도 분하지만, 당장으로서는…….","JPN":"私も悔しいですが、今は……","ENG":"I'm frustrated too, but right now, we just...","TWN":"我也很不甘心，但現在……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"답지 않게 약한 모습을 보이는군, 메데이아 경.","JPN":"弱い姿を見せるなど、らしくないな。メデイア卿。","ENG":"That doesn't sound like you, Dame Medea.","TWN":"真不像你，居然露出了軟弱的一面，美狄亞。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"연속된 패전이 그대에게 영향을 미친 건가?","JPN":"立てつづけの敗戦がそなたを萎縮させてしまったのか？","ENG":"Have the back-to-back defeats finally broken you?","TWN":"連續的敗戰對你產生了影響嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"그렇다면 실로 안타까워.","JPN":"ならば実に残念だ。","ENG":"If so, that would be quite a shame.","TWN":"那真是太可惜了。"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L44_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"전임 기사단장이나 부단장만큼은 아니지만, 난 그대를 제법 높게 평가하고 있었거든.","JPN":"前騎士団長や副団長とまではいかなくても、俺はそなたを高く評価していたんだがな。","ENG":"You might not match for former captain or deputy, but I had some respect for you.","TWN":"雖然不如前任騎士團長或副團長，但我對你的評價還是相當高的。"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"뭐야. 저 녀석, 갑자기 어디서 나타난 거야?!","JPN":"なによ、あいつ。どこから現れたの！？","ENG":"What the–?! Where did he come from?!","TWN":"什麼呀。那傢伙突然從哪兒冒出來的？"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"통신이군요. 이전 작전 때와 마찬가지로 기사단의 전산망을 장악한 거예요.","JPN":"通信ですね。この前の作戦と同じように、騎士団のネットワークを乗っ取ったんです。","ENG":"It's the comms. Just like last time, he's hijacked the Order's comms network.","TWN":"通訊啊。和之前的作戰一樣，已經掌握了騎士團的電腦網路。"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"카란티시르…!","JPN":"カランティシル……！","ENG":"Carantisir...!","TWN":"卡蘭堤西爾……！"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"에리어스는, 에리어스는 어떻게 한 거냐!!","JPN":"アリウスは、アリウスはどうした！！","ENG":"What have you done to Dame Arius?!","TWN":"埃里奧斯，他到底做了什麼！！"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"짖지 마라, 미천한 것. 너 따위가 내게 발언할 자격이 있다고 생각하는가?","JPN":"吠えるな、下賤の者。貴様ごときが俺に口を利く資格があるとでも思っているのか？","ENG":"Watch your tongue, filth. You think you have the right to speak to me?","TWN":"別叫，卑微的東西。你以為你有資格對我說話嗎？"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"네놈……!!","JPN":"貴様……！！","ENG":"Why you...!","TWN":"你這傢伙……！！"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"당신이 아무 이유 없이 이런 짓을 벌일 리는 없겠죠.","JPN":"あなたが何の理由もなくこんなことをするわけありませんわ。","ENG":"You wouldn't go this far without a reason.","TWN":"你不可能毫無理由地做這種事情吧。"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"본부의 전산망까지 장악한 뒤, 저희에게 무슨 말을 하고 싶은 거죠?","JPN":"本部のネットワークまで乗っ取り、私たちに何が言いたいのですか？","ENG":"What message are you trying to send by hijacking our entire network?","TWN":"在掌控了總部的電腦網路後，你想對我們說些什麼？"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"흥. 연회가 준비되었으니 손님 수를 맞추려는 것뿐이다.","JPN":"ふむ。用意された宴会の招待客数を合わせようとしているだけだ。","ENG":"Just making sure there are enough guests for the banquet.","TWN":"哼。只是為了準備宴會，才要湊齊客人的人數而已。"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"에스퀘데의 여식을 구하고 싶다면…….","JPN":"エスクェーデの娘を助けたいのなら……","ENG":"If you want to save Esquede's daughter...","TWN":"如果你想救出埃斯庫德的女兒……"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"그대들에게도 익숙한, 클리포트 게임의 현장이었던 곳으로 오도록.","JPN":"そなたたちにも馴染みの、クリフォトゲームの現場だった場所まで来い。","ENG":"Come to the place you're already familiar with. The Qliphoth Game's former battleground.","TWN":"請到那個你們也熟悉的逆卡巴拉遊戲現場來吧。"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"클리포트 게임? 뭐야, 무슨 마왕 노릇이라도 하겠다는 거야?","JPN":"クリフォトゲーム？　魔王ごっこでもするつもり？","ENG":"The Qliphoth Game? What, does he think he's the Demon Lord now?","TWN":"逆卡巴拉遊戲？什麼啊，難道是要扮演魔王嗎？"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"방식은 고사하고 장소를 지정했다는 것은 곧 전면전을 선언한 것이나 다름없습니다.","JPN":"やり方はさておき、場所を指定したというのは全面戦争を宣言したようなものです。","ENG":"Regardless of the rules, the fact that he's chosen the battlefield himself is essentially a declaration of war.","TWN":"別說方式了，指定地點就等於宣告全面戰爭了。"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"다른 태스크포스의 개입이 가능한 이상, 당신들에게 이로울 부분은 없을 텐데요?","JPN":"他のタスクフォースが介入できる以上、あなたたちに利はないはずですよ。","ENG":"And if other TASKFORCEs intervene, they stand to gain nothing. It's an outright provocation.","TWN":"既然其他特遣勢力可以介入，對你們來說應該沒有什麼好處吧？"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"이해득실을 배제한 채 기사단을 위해 나서려는 이가 과연 몇이나 될지 궁금하군.","JPN":"利害得失を顧みず、騎士団のために戦う者がどれほどいるのか気になるところだ。","ENG":"I wonder how many of you would act for the Order with no promise of gain.","TWN":"我很好奇，有多少人會在不計較個人得失的情況下，為騎士團挺身而出。"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"같잖은 도발에 응수하기를 원한 것이라면, 직접 보여줄 수는 있다만?","JPN":"くだらない挑発に乗ってほしいのなら、直接見せてやろうか。","ENG":"If you're hoping to see a reaction to such childish provocation, I can show you one myself.","TWN":"如果你想讓我回應這種無聊的挑釁，我倒是可以親自給你看看？"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"분개할 필요 없다. 기사의 결투라면 응당 그에 맞춘 형식을 따를 테니.","JPN":"憤慨する必要はない。騎士の決闘なら、それに応じた形式に従おう。","ENG":"No need to get worked up. If it's a knight's duel, I'll follow the proper formalities.","TWN":"無需憤怒。若是騎士的決鬥，自然會遵循相應的形式。"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_C_ARROW_IN_TRAILER_15"},{"id":"L20_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"선언하지.","JPN":"宣言する。","ENG":"I hereby declare.","TWN":"宣言吧。"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_C_ARROW_IN_TRAILER_16"},{"id":"L27_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"우리는 사령술의 힘으로 만들어낸 도플갱어 타입 침식체들을 앞세울 거다.","JPN":"俺たちは死霊術の力で作り出したドッペルゲンガータイプの侵食体を先鋒に出すつもりだ。","ENG":"We'll deploy Doppelganger-type C.O.s forged through necromancy.","TWN":"我們將派出利用死靈術之力製造的二重身型侵蝕體。"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_C_ARROW_IN_TRAILER_17"},{"id":"L28_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"그건 네놈들 전문인 일반적인 그림자와는 달리, 실제 살아있었던 인간일지도 모르지.","JPN":"それは貴様らの専門である一般的なシャドウとは違い、実際生きていた人間かもしれない。","ENG":"Unlike the Shadows you specialize in, these may have once been actual, living humans.","TWN":"那可能不是你們擅長的普通暗影，而是曾經活生生的人類。"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_C_ARROW_IN_TRAILER_18"},{"id":"L35_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"또한 레드시프트는 전력으로 블루시프트를 죽이려 들 거다.","JPN":"また、レッドシフトは全力でブルーシフトを殺す。","ENG":"And Red Shift will fight at full strength to wipe out Blue Shift.","TWN":"此外，紅移會全力以赴地試圖殺死藍移。"},"stage":{"bg":"CHURCH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_C_ARROW_IN_TRAILER_19"},{"id":"L36_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"네놈들에게 누군가를 죽이기 위한 검을 휘두를 각오가 되었다면.","JPN":"貴様らに誰かを殺すための剣を振り回す覚悟があるなら。","ENG":"If you're ready to swing your sword to kill...","TWN":"如果你們已經做好揮劍殺人的準備。"},"stage":{"bg":"CHURCH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_C_ARROW_IN_TRAILER_20"},{"id":"L37_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"모든 긍지를 걸고 우리에게 맞서라.","JPN":"すべての誇りをかけ、我らに立ち向かえ。","ENG":"Come face us with every ounce of your pride.","TWN":"以所有的驕傲與我們對抗吧。"},"stage":{"bg":"CHURCH","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_C_ARROW_IN_TRAILER_21"},{"id":"L40_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"고리타분한 과거를 답습하느냐, 규율을 위한 영달을 추구하느냐…….","JPN":"くだらない過去を踏襲するか、規律のための繁栄を追求するか……","ENG":"Will you cling to the outdated traditions of the past, or chase glory in the name of order...","TWN":"是要重複陳舊的過去，還是追求為了規矩的榮耀……"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_C_ARROW_IN_TRAILER_22"},{"id":"L41_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"어리석은 선조의 과오를 어떻게 해소해야 할지, 그곳에서 확인하도록 하지.","JPN":"愚かな先祖の過ちをどう解消すべきか、そこで確認するとしよう。","ENG":"Let's see how you intend to resolve the foolish sins of your ancestors. I'll be waiting.","TWN":"你要如何消除先祖們愚蠢的錯誤，就讓我在那裡確認一下吧。"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_C_ARROW_IN_TRAILER_23"},{"id":"L44_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"멈춰요, 피오네.","JPN":"待ちなさい、フィオネ。","ENG":"Don't, Fione.","TWN":"停下來，菲奧尼。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"죄송합니다. 메데이아 경.","JPN":"申し訳ありません、メデイア卿。","ENG":"Apologies, Dame Medea.","TWN":"對不起，美狄亞。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"설령 명령 불복종이라 한들, 이번만큼은 제 의지를 관철할 수밖에 없을 것 같군요.","JPN":"たとえ命令不服従だとしても、今回だけは私の意志を貫くしかありません。","ENG":"Even if it means disobeying orders, I have no choice but to act on my own will this time.","TWN":"即便是不服從命令，這次我也只能貫徹自己的意志了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그래. 저쪽에서 대놓고 도발하는데 고민할 게 뭐가 있어?","JPN":"そうだよ。あっちで堂々と挑発してるのに、悩む必要ある？","ENG":"Exactly. After a provocation like that, what's there to debate?","TWN":"對啊。那邊都已經公開挑釁了，還有什麼好猶豫的？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"가서 한방 날린 뒤에, 에리어스를 구하자고.","JPN":"行って一発食らわして、アリウスを助けようよ。","ENG":"We go in, take them down, and rescue Dame Arius.","TWN":"去給他們一擊，然後救出埃里奧斯吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"저도 가겠습니다.","JPN":"私も行きます。","ENG":"I'm going too.","TWN":"我也會去。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"여기서 아무런 행동도 하지 않는다면, 제가 목표로 한 기사는 결코 될 수 없을 테니까요.","JPN":"ここで何もしないなら、私が目標とする騎士には決してなれないはずですから。","ENG":"If I do nothing now, I'll never become the knight I aspire to be.","TWN":"如果在這裡什麼都不做，我永遠無法成為我所追求的騎士。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"이, 이번만큼은 저도 굽히지 않을 겁니다!","JPN":"こ、今回だけは私も屈しません！","ENG":"I-I won't back down this time either!","TWN":"這次，我絕不會退讓！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L9_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"알아요. 여러분이 무슨 말을 하는지, 제가 모를 리가 없잖아요.","JPN":"わかりますわ。皆さんの言いたい事が何か、わからないわけがありません。","ENG":"I know. Of course I know what all of you are trying to say.","TWN":"我知道。你們在說什麼，我怎麼可能不知道呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"하지만, 고작 셋이서 뭘 어떻게…….","JPN":"でも、たかが3人で何をどうやって……","ENG":"But what can you just the three of you–","TWN":"但是，只有三個人能做什麼……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"셋이라니 섭섭한 말씀을 하시는군요, 메데이아 경.","JPN":"3人って、何をおっしゃるのですか？　メデイア卿。","ENG":"Only three? That's a bit rude, Dame Medea.","TWN":"三個人？你這話可真讓人傷心啊，美狄亞。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"무구의 선택을 받지 못했다 한들, 저희 역시 별을 추종하는 기사들이 아닙니까?","JPN":"武具に選ばれなかったとしても、私たちもまた星の追従者です。","ENG":"Even if we haven't been chosen by the Armaments, we're still knights who follow the stars.","TWN":"即使沒有被無垢選中，我們不也是追隨星星的騎士嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"현 가용 가능한 블루시프트 전원. 준비를 끝마쳤습니다.","JPN":"現在可用できるブルーシフト全員。準備ができています。","ENG":"All active Blue Shift knights are prepped and ready.","TWN":"可出動的藍移團員已準備完成。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"준비는 되었으니 언제든 출발하시죠.","JPN":"もう覚悟は出来ています。いつでも出発しましょう。","ENG":"Say the word, and we'll move out.","TWN":"準備好了，隨時可以出發。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"그놈들 처음부터 마음에 안 들었어! 이 참에 동료들의 복수를 제대로 해보자고!","JPN":"あいつら、最初から気に入らなかったんだよ！　この機会に仲間たちの仇をとってやろう！","ENG":"I've hated those guys from the start! Let's make them pay for our comrades!","TWN":"那些傢伙從一開始就讓我不爽！趁這個機會好好為同伴們報仇吧！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"그래! 두 번이나 싸워봤는데 세 번이 두렵겠어? 가서 에리어스 경을 구하자!!","JPN":"ああ！　2回も戦ったんだ、3回だって怖くない！　行って、アリウス卿を助けよう！！","ENG":"We've fought them twice already, what's a third round? Let's go get Dame Arius!!","TWN":"對！我們已經打過兩次了，難道還怕第三次嗎？去救埃里奧斯卿吧！！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"다, 다들 진정하세요. 레드시프트는 호승심만으로 이길 수 있는 상대가 아니라고요.","JPN":"み、皆さん、落ち着いてください。レッドシフトは負けん気だけで勝てるような相手ではありません。","ENG":"E-everyone, calm down! Red Shift isn't an enemy we can beat just with passion!","TWN":"大、大家冷靜一下。紅移不是僅憑好勝心就能打敗的對手啊。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"이런 상황에서 적의 꾐에 넘어가서 뭘 어쩌겠다고…….","JPN":"この状況で敵の挑発に乗ってどうするので……","ENG":"You're falling right into their trap! What are you all thinki—","TWN":"這種狀況下，中了敵人的圈套又能怎麼辦……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"자, 잠시만요. 전화 좀 받을게요.","JPN":"ま、待ってください。電話に出ます。","ENG":"H-hold on. Let me take this call.","TWN":"等、等一下。我接下電話。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"너…! 대체 뭘 하고 다니길래 잠수타다 이제야 연락하는 거야?","JPN":"あなた……！　いったいどこで何をしてるの？　今更連絡寄越して。","ENG":"You...! Where have you been?! Why are you only calling now?!","TWN":"你……！到底在忙什麼，居然失蹤了這麼久才聯絡我？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"지금 본부 상황이 어떤 줄 알아?","JPN":"今の本部がどういう状況かわかってる！？","ENG":"Do you even realize what's going on at HQ right now?!","TWN":"你知道現在總部的情況嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"내 알 바니? 직위도 낮은 게 어따 대고 신경질이야?","JPN":"知らないわよ。私より職位も下のくせに、怒らないでくれる？","ENG":"How should I know? Who are you to yell at me, with your low rank?","TWN":"關我什麼事？職位低還在這裡發什麼脾氣？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L35_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"야! 나 지금 원로원이라 너보다 계급 높거든!?","JPN":"ちょっと！　私は今元老院で、あなたより職位が高いわよ！！","ENG":"Excuse me?! I'm with the Elders now! I outrank you!","TWN":"喂！我現在是元老院成員，比你級別高喔！"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"애초에 네가 작전 당일에 잠수만 안 탔어도 이렇게까지 몰리진 않았다고!","JPN":"そもそもあなたが作戦の当日にいなくなるからこんなことになってるの！","ENG":"If you hadn't ghosted on us the day of the mission, we wouldn't be in this mess to begin with!","TWN":"如果你在行動當天沒有失蹤的話，我們就不會被逼到這種地步了！"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"거 더럽게 징징대네. 나 없이 망할 기사단이면 그냥 망하는 게 낫지 않아?","JPN":"もう、うるさいわね。私がいないと何もできない騎士団なんて、なくなった方がいいんじゃないの？","ENG":"Geez, stop whining. If the Order's that pathetic without me, maybe it should just collapse.","TWN":"真是煩人的抱怨啊。如果沒有我這個騎士團會完蛋，那還不如就讓它完蛋吧？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"됐고, 다른 녀석들이 뭘 하고 있는 지나 말해. 상황은 TRS로 대충 파악했으니까.","JPN":"それはそうとして、他のやつらが何をしているのか話して。状況はTRSでだいたい把握してるわ。","ENG":"Anyway, just tell me what the others are doing. I've already gotten the gist through TRS.","TWN":"好了，告訴我其他傢伙在做什麼。我已經通過TRS大致了解了情況。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"그걸 몰라서 물어? 당장 쳐들어가겠다고 이곳저곳에서 난리야.","JPN":"決まってるじゃない。みんなすぐにでも行くって大騒ぎよ。","ENG":"Isn't it obvious?! Everyone's scrambling to go in. It's chaos out here!","TWN":"難道還用問嗎？到處都在鬧著要立刻進攻。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"바보들도 아니고, 아무리 인질이 잡혀 있다지만 함정일 확률이 다분한데…!","JPN":"バカでもあるまいし、いくら人質がいると言っても罠である確率が高いのに……！","ENG":"They're not idiots. They know it's probably a trap, even with Arius as a hostage...!","TWN":"我們又不是傻子，雖然有人質被抓，但這很可能是個陷阱…！"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"잘 됐네. 그럼 그쯤에서 합류하자고.","JPN":"ちょうどよかったわ。じゃあ、そこら辺で合流しましょう。","ENG":"Perfect. I'll meet you there, then.","TWN":"太好了！那我們就在那邊會合吧。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"방해되지 않게 눈치 챙기는 것도 잊지 마라?","JPN":"邪魔にならないように、空気読みなさいよ？","ENG":"And hey, don't forget to read the room and not to get in my way, all right?","TWN":"別忘了察言觀色，不要妨礙到別人喔？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"뭐?","JPN":"え？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"하, 그래. 기사단엔 죄다 바보들밖에 없었지.","JPN":"は、そうだわ。騎士団にはバカしかいないの、忘れてた。","ENG":"*Sigh* Right. Of course, everyone in this Order is an idiot.","TWN":"下，沒錯。騎士團裡全都是傻瓜。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"아아-! 나도 이제 몰라!!","JPN":"ああー！　もう、私も知らない！！","ENG":"Aah! Whatever!","TWN":"啊啊——！我也不知道了！！"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"함선에 물자 싣고, 전원 전투 상태로 대기하세요. 이렇게 된 이상 전면전으로 갑니다!","JPN":"艦船に物資を乗せて、全員戦闘状態で待機してください。こうなった以上、全面戦争で行きます！","ENG":"Load supplies onto the ship! Full combat readiness, everyone! We're going in, all out!","TWN":"把物資裝上艦船，全員進入戰鬥狀態待命。既然如此，就全面開戰吧！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"불만 있는 사람, 거수!","JPN":"文句ある人、挙手！","ENG":"Anyone got a problem with that? Raise your hand!","TWN":"誰有問題，舉手！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"인도자께서 점지해주신 별의 궤도에, 우리의 정의를 드높이겠습니다!","JPN":"導き手が教えてくれた星の軌道に、我らの正義を轟かせます！","ENG":"We'll raise our justice high along the orbit marked by the Star Guide!","TWN":"在引導者指引的星軌上，我們將高舉我們的正義！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"네에-! 없겠죠, 그렇겠죠!!","JPN":"はいはい！　いないわよね、そうでしょうね！！","ENG":"Yup! That's what I thought!!","TWN":"好耶——！不會有的吧，是這樣吧！！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"야, 한솔아. 어째 너네 누님 성격이 바뀐 것 같다?","JPN":"ねえ、イチロウ。あなたのところのお姉さん、なんかキャラ変わってない？","ENG":"Hey, Hansol. Is it just me, or did your sister's personality totally flip?","TWN":"嘿，楊瀚，你姊姊的性格好像變了？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"그, 글쎄요? 무슨 말씀인지 저는 잘…….","JPN":"さ、さあ？　どういうことだか、さっぱり……","ENG":"I-I have no idea what you're talking about...","TWN":"這、這個嗎？你說的我不太……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"기사단의 예봉으로서 더 이상의 실패는 용납될 수 없다.","JPN":"騎士団の鋭鋒として、これ以上の失敗は許されない。","ENG":"As the spearhead of the Order, we cannot afford another failure.","TWN":"作為騎士團的先鋒，不能再容許失敗了。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"이번에야말로 반드시…….","JPN":"今度こそ、必ず……","ENG":"This time, we will...","TWN":"這次，一定要"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……지금까지의 과오를 바로잡는다.","JPN":"……今までの過ちを立て直す。","ENG":"...Make up for all our past mistakes.","TWN":"……糾正至今為止的過錯。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"더는, 무엇도 잃지 않아.","JPN":"もう、何も失わない。","ENG":"I won't lose anything ever again.","TWN":"再也不會失去任何東西了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"그것이 나의 정의이자, 또한 기사로서의 긍지다.","JPN":"それが俺の正義であり、また騎士としての誇りだ。","ENG":"That is my definition of justice... and the pride I hold as a knight.","TWN":"這是我的正義之座，也是作為騎士的自豪。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"네놈들이 아무리 발악한들… 결과는 달라지지 않아.","JPN":"貴様らがいくら足掻こうとも……結果は変わらない。","ENG":"No matter how desperately you struggle… the outcome will not change.","TWN":"你們再怎麼掙扎，結果也不會改變。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"자아, 개전이다.","JPN":"さあ、開戦だ。","ENG":"Now, let the battle begin.","TWN":"好了，開戰吧。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_C_ARROW_IN_TRAILER_24"},{"id":"L32_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"와라, 블루시프트.","JPN":"来い、ブルーシフト。","ENG":"Come, Blue Shift.","TWN":"來吧，藍移。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_C_ARROW_IN_TRAILER_25"}]`);export{e as default};